mapper.select:
SELECT COUNT(1)
FROM feedback f
WHERE f.delete_flag = 0
AND f.user_id = #{query.userId}


    AND f.target_type = #{query.targetType}



    AND f.feedback_result = #{query.feedbackResult}

SELECT f.id, f.user_id, NULL AS username, f.target_type, f.target_id, f.feedback_result, f.content, f.gmt_create FROM feedback f WHERE f.delete_flag = 0 AND f.user_id = #{query.userId}
AND f.target_type = #{query.targetType}
AND f.feedback_result = #{query.feedbackResult}
ORDER BY f.gmt_create DESC, f.id DESC LIMIT #{query.offset}, #{query.pageSize}

SELECT m.chat_id AS chat_id, NULL AS question, m.image_analysis AS image_analysis, CASE WHEN CHAR_LENGTH(m.content) > 200 THEN CONCAT(SUBSTRING(m.content, 1, 200), '...') ELSE m.content END AS answer_summary FROM ai_chat_message m WHERE m.id = #{messageId} AND m.role = 'assistant' AND m.message_status IN ('COMPLETED', 'STOPPED') AND m.delete_flag = 0
AND m.message_type = #{messageType}
LIMIT 1
